```java
@Service class ProductService {
    @Cacheable("products")
    public String findAll() {
        System.out.println("DB HIT");
        return "[Mouse, Keyboard]";
    }
}
// Called in order:
service.findAll();  // 1
service.findAll();  // 2
service.findAll();  // 3
cacheManager.getCache("products").clear();
service.findAll();  // 4
service.findAll();  // 5
```

