@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.NONE)
class CountryCacheTest {
    @Autowired CountryService service;
    @Autowired CacheManager cacheManager;

    @BeforeEach
    void clearCache() {
        cacheManager.getCacheNames()
            .forEach(name -> cacheManager.getCache(name).clear());
    }

    @Test
    void findAll_calledTwice_sameResultAndCachePopulated() {
        var result1 = service.findAll();
        var result2 = service.findAll();

        assertEquals(result1, result2);

        Cache cache = cacheManager.getCache("countries");
        assertNotNull(cache.get(SimpleKey.EMPTY),
            "Cache should have an entry after findAll()");
    }

    @Test
    void save_evictsCache_freshFetchOnNextCall() {
        service.findAll();  // populate
        service.save("IN", "India");  // should evict

        // Cache entry should be gone:
        Cache cache = cacheManager.getCache("countries");
        assertNull(cache.get(SimpleKey.EMPTY),
            "Cache should be empty after save()");

        // Next call re-populates:
        service.findAll();
        assertNotNull(cache.get(SimpleKey.EMPTY));
    }
}

