import org.springframework.cache.annotation.Cacheable;
import java.util.*;
import org.springframework.stereotype.Service;

@Service
public class SearchService {

    // condition: only cache if query is 3+ chars:
    @Cacheable(value = "search", key = "#query",
               condition = "#query != null && #query.length() >= 3")
    public List<String> search(String query) {
        System.out.println("DB: search('" + query + "')");
        return List.of("Result for " + query);
    }

    // unless: don't cache if n > 100 (too large to cache efficiently):
    @Cacheable(value = "search", key = "'top:' + #n",
               unless = "#n > 100")
    public List<String> findTop(int n) {
        System.out.println("DB: findTop(" + n + ")");
        return List.of("Top " + n);
    }

    // unless: don't cache empty results:
    @Cacheable(value = "search",
               key = "#min + ':' + #max",
               unless = "#result == null || #result.isEmpty()")
    public List<String> findByPriceRange(double min, double max) {
        System.out.println("DB: findByPriceRange(" + min + "," + max + ")");
        // Returns empty for very large range in this simulation:
        return min > 1000000 ? List.of() : List.of("Product in range");
    }
}

