import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.cache.*;
import org.springframework.cache.interceptor.SimpleKey;
import org.mockito.Mockito;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;
import org.junit.jupiter.api.*;
import java.util.List;

// Note: Testing with a real @DataJpaTest repository spy is complex.
// Here we demonstrate the pattern with a counter-based approach:

@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.NONE)
class ProductCacheSpyTest {
    @Autowired ProductService service;
    @Autowired CacheManager cacheManager;
    @Autowired ProductRepository repo;

    @BeforeEach void setup() {
        cacheManager.getCacheNames().forEach(n -> cacheManager.getCache(n).clear());
        repo.deleteAll();
        repo.save(new Product("Mouse",799,"Electronics"));
    }

    @Test
    void findAll_twice_onlyOneDbHit() {
        var result1 = service.findAll();
        var result2 = service.findAll();
        assertEquals(result1, result2);
        // Cache hit after first call:
        assertNotNull(cacheManager.getCache("products").get(SimpleKey.EMPTY));
    }

    @Test
    void saveAndFindAll_cacheMissAfterEviction() {
        service.findAll();  // populate cache
        assertNotNull(cacheManager.getCache("products").get(SimpleKey.EMPTY));

        service.save(new Product("Keyboard",1999,"Electronics"));  // evict
        assertNull(cacheManager.getCache("products").get(SimpleKey.EMPTY));  // evicted!

        service.findAll();  // re-populate
        assertNotNull(cacheManager.getCache("products").get(SimpleKey.EMPTY));  // fresh
    }
}

// ProductCatalogService:
import org.springframework.cache.annotation.*;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import java.util.*;

@Service @Transactional
public class ProductCatalogService {
    private final ProductRepository repo;
    ProductCatalogService(ProductRepository r) { repo = r; }

    @Cacheable("products")
    public List<Product> findAll() { return repo.findAll(); }

    @Cacheable(value="products", key="#id")
    public Optional<Product> findById(String id) { return repo.findById(id); }

    @Cacheable(value="products", key="'cat:'+#category")
    public List<Product> findByCategory(String category) { return repo.findByCategory(category); }

    @Caching(
        put  = @CachePut(value="products", key="#result.id"),
        evict = {
            @CacheEvict(value="products", allEntries=true),  // clear list caches
        }
    )
    public Product save(Product p) { return repo.save(p); }

    @Caching(
        put  = @CachePut(value="products", key="#id"),
        evict = @CacheEvict(value="products", allEntries=true)
    )
    public Product update(String id, Product p) {
        Product existing = repo.findById(id).orElseThrow();
        existing.setName(p.getName()); existing.setPrice(p.getPrice());
        return repo.save(existing);
    }

    @Caching(evict = {
        @CacheEvict(value="products", key="#id"),
        @CacheEvict(value="products", allEntries=true)
    })
    public void delete(String id) { repo.deleteById(id); }
}

