import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.cache.*;
import org.springframework.cache.interceptor.SimpleKey;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@SpringBootTest(webEnvironment=SpringBootTest.WebEnvironment.NONE)
class ProductCatalogCacheTest {
    @Autowired ProductCatalogService service;
    @Autowired CacheManager cacheManager;
    @Autowired ProductRepository repo;

    @BeforeEach void setup() {
        cacheManager.getCacheNames().forEach(n->cacheManager.getCache(n).clear());
        repo.deleteAll();
        repo.save(new Product("Mouse",799,"Electronics"));
    }

    Cache cache() { return cacheManager.getCache("products"); }

    @Test void findAll_populatesCache() {
        service.findAll();
        assertNotNull(cache().get(SimpleKey.EMPTY));
    }
    @Test void findById_cachesPerProduct() {
        Product p = repo.findAll().get(0);
        service.findById(p.getId());
        assertNotNull(cache().get(p.getId()));
    }
    @Test void save_evictsListCache() {
        service.findAll();
        service.save(new Product("KB",1999,"Electronics"));
        assertNull(cache().get(SimpleKey.EMPTY));
    }
    @Test void delete_evictsBothEntries() {
        Product p = repo.findAll().get(0);
        service.findAll(); service.findById(p.getId());
        service.delete(p.getId());
        assertNull(cache().get(SimpleKey.EMPTY));
        assertNull(cache().get(p.getId()));
    }
}

