import org.springframework.cache.CacheManager;
import org.springframework.cache.caffeine.CaffeineCacheManager;
import org.springframework.context.annotation.*;
import com.github.benmanes.caffeine.cache.Caffeine;
import java.time.Duration;

@Configuration
class CachePriceOverride {
    // The @Bean approach overrides the application.properties setting:
    @Bean
    public CacheManager cacheManager() {
        CaffeineCacheManager manager = new CaffeineCacheManager();
        // Global spec for non-overridden caches:
        manager.setCaffeine(Caffeine.newBuilder()
            .maximumSize(1000).expireAfterWrite(Duration.ofMinutes(5)));
        // Override prices with 30s TTL:
        manager.registerCustomCache("prices",
            Caffeine.newBuilder().maximumSize(200)
                .expireAfterWrite(Duration.ofSeconds(30)).build());
        return manager;
    }
}

